const aermini_embed_picture = "data:image/png;base64,";
const aermini_embed_icon = "";
const aermini_embed_extensionId = "AerStrFuzzy";

/** @typedef {string|number|boolean} SCarg */
class AerStrFuzzy {
    constructor(runtime) {
        this.runtime = runtime;
        this._formatMessage = runtime.getFormatMessage({
            "zh-cn": {
                "AerStrFuzzy.name": "AerMini的字符串匹配",
                "AerStrFuzzy.block1": "字符串[string1]和[string2]的相似度",
                "AerStrFuzzy.block3": "字符串[string1]和[string2]相匹配?(普遍)",
                "AerStrFuzzy.block4": "字符串[string1]和[string2]的相似度",
            },
            en: {
                "AerStrFuzzy.name": "AerMini's String Matching",
                "AerStrFuzzy.block1": "String similarity between[string1]and[string2]",
                "AerStrFuzzy.block3": "String[string1]and[string2]match?(Universal)",
                "AerStrFuzzy.block4": "字符串[string1]和[string2]的相似度",
            }
        })
    }
    /**
     * @param {string} id
     * @return {string}
     */
    formatMessage(id) {
        return this._formatMessage({
            id,
            default: id,
            description: id
        });
    }

    getInfo() {
        return {
            id: aermini_embed_extensionId,
            name: this.formatMessage("AerStrFuzzy.name"),
            blockIconURI: aermini_embed_icon,
            menuIconURI: aermini_embed_icon,
            color1: "#cecb1f",
            color2: "#fffb17",
            blocks: [
                {
                    opcode: "bl1",
                    blockType: "reporter",
                    text: this.formatMessage("AerStrFuzzy.block1"),
                    arguments: {
                        string1: {
                            type: "string",
                            defaultValue: "",
                        },
                        string2: {
                            type: "string",
                            defaultValue: "",
                        }
                    },
                },
                {
                    opcode: "bl3",
                    blockType: "Boolean",
                    text: this.formatMessage("AerStrFuzzy.block3"),
                    arguments: {
                        string1: {
                            type: "string",
                            defaultValue: "",
                        },
                        string2: {
                            type: "string",
                            defaultValue: "",
                        }
                    },
                },
                {
                    opcode: "bl4",
                    blockType: "reporter",
                    text: this.formatMessage("AerStrFuzzy.block4"),
                    arguments: {
                        string1: {
                            type: "string",
                            defaultValue: "",
                        },
                        string2: {
                            type: "string",
                            defaultValue: "",
                        }
                    },
                }
            ],
            menus: {
			}
        };
    }
    
    bl1(args) {
        function levenshteinDistance(a, b) {
            const matrix = [];
            if (a.length === 0) return b.length;
            if (b.length === 0) return a.length;
            for (let i = 0; i <= b.length; i++) {
                matrix[i] = [i];
            }
            for (let j = 0; j <= a.length; j++) {
                matrix[0][j] = j;
            }
            for (let i = 1; i <= b.length; i++) {
                for (let j = 1; j <= a.length; j++) {
                    if (b.charAt(i - 1) === a.charAt(j - 1)) {
                        matrix[i][j] = matrix[i - 1][j - 1];
                    } else {
                        matrix[i][j] = Math.min(
                            matrix[i - 1][j - 1] + 1, 
                            matrix[i][j - 1] + 1,     
                            matrix[i - 1][j] + 1      
                        );
                    }
                }
            }
            return matrix[b.length][a.length];
        }
        
        function similarity(str1, str2) {
            str1 = String(str1);
            str2 = String(str2);
            if (!str1 && !str2) return 1.0;
            let distance = levenshteinDistance(str1, str2);
            let maxLength = Math.max(str1.length, str2.length);
            let similarityScore = maxLength > 0 ? (maxLength - distance) / maxLength : 1.0;
            return parseFloat(similarityScore.toFixed(5));
        }

        return similarity(args.string1, args.string2)
    }

    bl3(args) {
    	function calculateSimilarity(mainStr, searchStr, textWeight = 0.8, digitWeight = 0.2) {
            mainStr = String(mainStr).toLowerCase();
            searchStr = String(searchStr).toLowerCase();
            const cleanMainStr = mainStr.replace(/\s*$[^)]*$\s*/g, '');
            const cleanSearchStr = searchStr.replace(/\s*$[^)]*$\s*/g, '');
            const isMainAllDigits = /^\d+$/.test(cleanMainStr);
            const isSearchAllDigits = /^\d+$/.test(cleanSearchStr);
            if (isMainAllDigits && isSearchAllDigits && cleanMainStr !== cleanSearchStr) {
                return false;
            }
            if (cleanMainStr.length <= 2 || cleanSearchStr.length <= 2) {
                return cleanMainStr === cleanSearchStr;
            }
            let maxLength = Math.max(cleanMainStr.length, cleanSearchStr.length);
            let distance = levenshteinDistance(cleanMainStr, cleanSearchStr);
            let overallSimilarity = maxLength > 0 ? (maxLength - distance) / maxLength : 1.0;
            const onlyDigitsMain = cleanMainStr.replace(/\D/g, '');
            const onlyDigitsSearch = cleanSearchStr.replace(/\D/g, '');
            let digitDistance = levenshteinDistance(onlyDigitsMain, onlyDigitsSearch);
            let digitMaxLength = Math.max(onlyDigitsMain.length, onlyDigitsSearch.length);
            let digitSimilarity = digitMaxLength > 0 ? (digitMaxLength - digitDistance) / digitMaxLength : 1.0;
            let finalSimilarity = textWeight * overallSimilarity + digitWeight * digitSimilarity;
            console.log(`Overall similarity: ${overallSimilarity.toFixed(5)}, Digit similarity: ${digitSimilarity.toFixed(5)}, Final similarity: ${finalSimilarity.toFixed(5)}`);
            const minLengthThreshold = 8;
            const shortStringThreshold = 0.45;
            const longStringThreshold = 0.25;
            if (cleanMainStr.length <= 2 || cleanSearchStr.length <= 2) {
                return cleanMainStr === cleanSearchStr;
            } else if (cleanMainStr.length <= minLengthThreshold || cleanSearchStr.length <= minLengthThreshold) {
                return finalSimilarity >= shortStringThreshold;
            } else {
                return finalSimilarity >= longStringThreshold;
            }
        }
        
        function levenshteinDistance(a, b) {
            const matrix = [];
            if (a.length === 0) return b.length;
            if (b.length === 0) return a.length;
            for (let i = 0; i <= b.length; i++) {
                matrix[i] = [i];
            }
            for (let j = 0; j <= a.length; j++) {
                matrix[0][j] = j;
            }
            for (let i = 1; i <= b.length; i++) {
                for (let j = 1; j <= a.length; j++) {
                    if (b.charAt(i - 1) === a.charAt(j - 1)) {
                        matrix[i][j] = matrix[i - 1][j - 1];
                    } else {
                        matrix[i][j] = Math.min(
                            matrix[i - 1][j - 1] + 1,
                            matrix[i][j - 1] + 1,
                            matrix[i - 1][j] + 1
                        );
                    }
                }
            }
            return matrix[b.length][a.length];
        }

        return calculateSimilarity(args.string1, args.string2)
    }

    bl4(args) {
        function levenshteinSimilarity(s1, s2) {
            function levenshtein(s1, s2) {
                if (s1.length < s2.length) return levenshtein(s2, s1);
        
                if (s2.length === 0) return s1.length;
        
                let previousRow = Array.from({ length: s2.length + 1 }, (_, i) => i);
                for (let i = 0; i < s1.length; i++) {
                    let currentRow = [i + 1];
                    for (let j = 0; j < s2.length; j++) {
                        let insertions = previousRow[j + 1] + 1;
                        let deletions = currentRow[j] + 1;
                        let substitutions = previousRow[j] + (s1[i] !== s2[j]);
                        currentRow.push(Math.min(insertions, deletions, substitutions));
                    }
                    previousRow = currentRow;
                }
                return previousRow[previousRow.length - 1];
            }
        
            const distance = levenshtein(s1, s2);
            const maxLength = Math.max(s1.length, s2.length);
            return maxLength > 0 ? 1 - distance / maxLength : 1;
        }
        
        function preprocessString(s) {
            // 确保输入是字符串类型
            s = String(s);
            
            // 将字符串转换为小写（适用于英文），并移除非字母数字字符（但保留中文字符）
            return s.toLowerCase().replace(/[^\w\u4e00-\u9fff]+/g, '');
        }
        
        function fuzzyMatchPrefix(str1, str2, prefixLength = 7) {
            // 预处理输入字符串
            str1 = preprocessString(str1);
            str2 = preprocessString(str2);
        
            // 检查是否有共同的前缀，使用最小长度以避免索引错误
            const minLength = Math.min(str1.length, str2.length, prefixLength);
            const commonPrefix = str1.substring(0, minLength) === str2.substring(0, minLength);
            
            // 如果有共同前缀，则认为匹配成功
            return commonPrefix;
        }

        levenshteinSimilarity(String(args.string1), String(args.string2))
    }
}

